import { h, Fragment } from 'preact';
import { useRef, useState, useEffect } from 'preact/hooks';
import { configs } from '/configs';
import { useStore, getStore } from '/store';
import { FootnoteRenderer } from '/foonoterenderer';
import { useInstaller } from 'preact-pwa-install';





export function PageFooter(props) {
	const [isPlaying, setIsPlaying] = useState(false);
	const audioElem = useRef(null);
	const audioI = useRef(null);
	const playButton = useRef(null);
	const nextButton = useRef(null);
	const prevButton = useRef(null);

	
	const setupButton = (btn, path) => {
		if (btn.current){
			if (path === ''){
				btn.current.style.visibility = 'hidden';
				//btn.current.disabled = true;
			} else {
				btn.current.style.visibility = 'visible';
				//btn.current.disabled = false;
			}		
		}
	}

	useEffect(() => {
		setupButton(nextButton, props.audioManager.nextAudioPath);
	}, [props.audioManager.nextAudioPath]);

	useEffect(() => {
		setupButton(prevButton, props.audioManager.prevAudioPath);
	}, [props.audioManager.prevAudioPath]);


	useEffect(() => {
		
		if (audioElem.current) {		
			if (isPlaying) {
				audioElem.current.pause()
				setIsPlaying(false);	
			}
			setupAudio(props.audioManager.audioPath);
			if (props.audioManager.audioPath !== '') {
				if (audioI.current){
					audioElem.current.src = configs.audioUrl + props.audioManager.audioPath;
					audioElem.current.play();
					audioI.current.innerHTML = 'pause';
					setIsPlaying(true);
				}
			}
		} else {
			setupAudio(props.audioManager.audioPath);
		}
	}, [props.audioManager.audioPath]);;

	const setupAudio = (audioUrl) => {
		if (playButton.current && audioElem.current){
			if (audioUrl === '') {
				playButton.current.style.visibility = 'hidden';
			} else {
				playButton.current.style.visibility = 'visible';
				//TODO hardcode url into python script that builds audio index, not here
				audioElem.current.src = configs.audioUrl + audioUrl;
			}
		}
	}
	
	
	const playAudio = (ev) => {
		if (audioElem.current && audioI.current){
			const audio = audioElem.current;
			if (isPlaying){
				setIsPlaying(false);
				audio.pause();
				audioI.current.innerHTML = 'play_arrow';
			} else {
				setIsPlaying(true);
				audio.play();
				audioI.current.innerHTML = 'pause';         
			}
		}
	}
	
	const nextPrevBtnClicked = (dir) => {
		if (dir ==='next'){
			props.audioManager.reportAudioNav(props.audioManager.nextAudioPath, props.audioManager.nextAudioNum);
		} else {
			props.audioManager.reportAudioNav(props.audioManager.prevAudioPath, props.audioManager.prevAudioNum);
		}
	};
		

	return (			
		<footer class="mdl-mini-footer" style="display:grid;grid-template-columns:1fr 1fr 1fr; grid-auto-rows: minmax(0px, auto);" id="toolbar-bottom">
			<div style="grid-row: 1; grid-column: 1 / 3;">
				<FootnoteRenderer 
					fnGloManager={props.fnGloManager}/>
			</div>
			
			<button 
				style="grid-column:1;grid-row:2;visibility:hidden;"
				class="mdl-button mdl-js-button mdl-button--fab"
				onclick={() => nextPrevBtnClicked('prev')}
				ref={prevButton}>
				<i class="material-icons">navigate_before</i>
			</button>
			<div class="mdl-button mdl-js-button mdl-button--fab" 
				style="grid-column:2;grid-row:2;visibility:hidden;"
				id="play-button"
				ref={playButton}
				onclick={playAudio}>
				<i class="material-icons" 
				id="play-btn-i"
				ref={audioI}></i>
			</div>
			<audio id="audio-elem" ref={audioElem} class="display:none;visibility:hidden;"></audio>
			<button 
				class="mdl-button mdl-js-button mdl-button--fab"
				style="visibility:hidden;grid-column:3;grid-row:2;"
				onclick={() => nextPrevBtnClicked('next')}
				ref={nextButton}>
				<i class="material-icons" disabled>navigate_next</i>
			</button>
		</footer>
	);
}





