
import createStore from "teaful";
import { bookData } from './bookData';
import { chapterData } from './chapterdata';


const initialBook = bookData[1]
const initialChapters = chapterData[initialBook.code]


let initialStore = {
    chapters: initialChapters,
    books: bookData,
    bookCode: '',
    installVisible: 'none',
    curName: '',
    curBook: initialBook,
    curChapter: initialChapters[0].number,
    xmlData: null,
    firstLoad: true,
    navTarget: '',
    navTargetSearch: ''
};


export const { useStore, getStore } = createStore(initialStore); 


export function setFragmentedStore(fields) {
    Object.entries(fields).forEach(([key, value]) => {
      getStore[key](value);
    });
  }