import { h, render, options } from 'preact';
import Markup  from 'preact-markup';
import { useEffect } from 'preact/hooks';
import { audioData } from './audiodata';
import { configs } from './configs';
import { fnmap } from './fnmap';
import { getStore, useStore } from './store';


const Verse = ({ style, number, sid, children }) => (
    <span class={style} id={sid}>{ number }</span>
);


function PageElement(props){
    const [bookCode, ] = useStore.bookCode();


    const Para = ({ style, children }) => {
        if (style === 'is' && children[0] === configs.book_intro_name){
            var pengId = bookCode + '-' + configs.book_intro_name;
            return (
                <div class={style} id={pengId}>
                    { children }
                </div>
            ); 
        }
        return (
            <div class={style}>
                { children }
            </div>
        );
    }


    const Chapter = ({ style, number, sid, children }) => {
        if (!number){
            return null;
        }
        
        if (props.navManager.bookCode in audioData && number in audioData[props.navManager.bookCode]){
            return (
                <div class="chapter-number-audio-wrapper" id={sid}>
                    <span class={style}>{ number }</span>
                    <button 
                        class="mdl-button mdl-js-button" 
                        onclick={() => props.audioManager.playAudio(audioData[props.navManager.bookCode][number], number)}>
                    dengerke
                    </button>
                </div>
            );
        } else {
            return (
                <div class="chapter-number-audio-wrapper" id={sid}>
                    <span class={style} >{ number }</span>
                </div>
            );
        }
    };


    const Note = ({ style, caller, children }) => {
        props.updateFnCounter();
        let counter = props.getNewFnCounter();
        return <span class={"footnote fnbodyhidden " + style} 
            onclick={() => props.fnGloManager.showParatextContent('FN', children)}><sup>{ counter }</sup></span>
    };


    const Ref = ({ loc, children }) => {
        const inApp = props.navManager.books.some(x => loc.includes(x.code));
        if (inApp) {
            return <span 
                    class="ref"
                    onclick={() => props.fnGloManager.showParatextContent('XR', [loc, children])}>{ children }</span>
        } else {
            return <span 
                    class="notinapp">{ children }</span>
        }
    };


    const Char = ({ style, children }) => {
        switch (style) {
            case 'w':
                return <span class={"glospan footnote " + style} 
                             onclick={() => props.fnGloManager.showParatextContent('GLO', children)}>{ children }</span>
                break;
            case 'fq': 
                props.fnGloManager.setFnTitle(children)
                return null;
                break;
            case 'fr': 
                    return null;
                    break;
            case 'xo':
                return null;
                break;
            case 'xt':
                return <span class={style} >{ children }</span>
                break;
            default:
                return <span class={style}>{ children }</span>
        }        
    };

    const Body = ({ children }) => {
        return <div>{children}</div>
    }



    return <Markup markup={props.cons.outerHTML} type="xml" trim={false} components={{ Para, Char, Chapter, Verse, Note, Ref, Body}} />
}



function filterElems(data) {
    if (['book'].includes(data.nodeName)) {
        return false;
    } else if(data.attributes.style){
        if (['toc', 'toc1', 'toc2', 'toc3', 'h'].includes(data.attributes.style.nodeValue)) {
            return false;
        }
    }
    return true;
}


export function BookRenderer(props)  {
    var fnCounter = 0;
    const incrementFnCaller = () => fnCounter = fnCounter + 1;
    const [ xmlData, ] = useStore.xmlData();
    const [navTarget, setNavTarget] = useStore.navTarget();

    
    useEffect(() => {
      //  console.log('!!! [useLayoutEffect]: navTarget === ' + navTarget);
        if (navTarget){
           // console.log('BookREnderer: navTarget === ' + navTarget);
            setTimeout(() => {
                var elem = document.getElementById(navTarget);
                if (elem) {
                    elem.scrollIntoView({behavior: "smooth", block: "start", inline: "start"});
                } else {
                    // console.log("!!!!!! BOOK RENDERER: elem was null!!!!!!")
                }
                setNavTarget('');
            }, 500)
        }
    }, [xmlData]);


    const getFnCounter = () => {        
        return fnmap[fnCounter];
    };

    
    const renderItems = (elems) => {
        if (!elems || elems.length < 1) {
            return [];
        }

        const items = [];

        for (const [i, item] of elems.entries()) {
            items.push(<PageElement 
                cons={item}
                navManager={props.navManager}
                audioManager={props.audioManager}
                fnGloManager={props.fnGloManager}
                getNewFnCounter={getFnCounter}
                setFnTitle={props.setFnTitle} 
                updateFnCounter={incrementFnCaller} />);
        }
        return items;
    };

//.filter(filterElems))}
    return (            
        <main class="mdl-layout__content" 
              
              id="mainelem">
            <div id="content">
                {xmlData && renderItems(Array.from(xmlData.firstChild.children))} 
            </div>
        </main>
    );
}