//import { h, render, Fragment } from 'preact';
import { useState, useRef } from 'preact/hooks';
import { bookData } from '/bookData';
import { configs } from '/configs';
//import style from './css/dropdown';
import { searchIndex } from '/searchData'
import { HeaderMenu } from '/pageheader'
import { _ , useStore } from '/store'
import Fuse from 'fuse.js'


const bookCodeMap = {};
bookData.forEach((x) => bookCodeMap[x.code] = x.name);


function SearchResultsDisplay(props) {
    //const [navTarget, setNavTarget] = useStore.navTarget();


    const goToResults = (address) => {
        //setNavTarget(address);
        props.navManager.navFromRef(address);
    };


    const convertRefCode = (x) => {
        var parts = x.split(' ');
        var code = parts[0];
        return bookCodeMap[code] + ' ' + parts.slice(1).join(' ');
    };

    return (
        props.results.map(res => {
            return (
            <div class="search-result-wrapper">
                <a class="search-results-a"
                   onclick={() => goToResults(res.item.ref)}>{convertRefCode(res.item.ref)}</a>
                <span class="search-results-text">{res.item.text}</span>
            </div>
            );
        })
    );

}

function SearchHeader(props) {
    const searchBar = useRef(null);
    const [value, setValue] = useState('');
    
    const searchFuse = new Fuse(searchIndex, {
		keys: ['text']
	});

	const doSearch = () => {
		//const sbox = document.getElementById('search-box');
		const searchBar = document.getElementById('search-div');

		if (searchBar) {
			searchBar.classList.remove('search-shown');
			searchBar.classList.add('search-hidden');
		}
		if (value) {
           // console.log(value);
			var res = searchFuse.search(value);
            props.setSearchResults(res);
		}
		
	}

    const onInput = (e) => {
        setValue(e.target.value);
    }

    const handleKeyPress = (e) => {
        if (e.key === 'Enter'){
            doSearch();
        }
    }


    return (
    <header class="mdl-layout__header"  id="header-bar" ref={toolbar}>
		<div class="navigation-top">		
            <img src="icons/icon-36.png" id="nav-app-icon" style="grid-column:1; grid-row:1; min-height:36px; min-width:36px;"></img>
            <a  style="grid-column:2 / span 2; grid-row:1; text-decoration:none;font-size:1.25em;color:white;"
                class="mdl-button mdl-js-button"
                href="/">{configs.home}</a>
            
            <HeaderMenu  
                style="grid-column:4; grid-row:1;min-height:36px; min-width:36px;"
                searchBar={searchBar} />
            <input type="text" 
                id="search-box" 
                style="grid-column: 1 / span 3;grid-row:2; margin-top:4px;"  
                value={value}
                onInput={onInput}
                onKeyUp={handleKeyPress}
                placeholder={configs.search} />
            <button onclick={doSearch}
                    style="grid-column: 4; grid-row: 2; background:#F0F0F0; margin-top:4px;"
                    class="mdl-button mdl-js-button" >{configs.search}</button>
            
        </div>
    </header>
    );
}

export function SearchPage(props) {
    const [searchResults, setSearchResults] = useState([]);

    return (
        <div class="mdl-layout mdl-js-layout mdl-layout--fixed-header">
            <SearchHeader setSearchResults={setSearchResults} />
            <SearchResultsDisplay 
                results={searchResults} 
                navManager={props.navManager}/>
        </div>
    );
}