import './css/style';
import { h, render, Component, toChildArray, cloneElement } from 'preact';
import { PageHeader } from '/pageheader';
import { BookRenderer } from '/bookRenderer';
import { useEffect, useRef, useState } from 'preact/hooks';
import { PageFooter } from '/pagefooter';
import { awaitInstallPrompt } from 'preact-pwa-install';
import { Router } from 'preact-router';
import { SearchPage } from '/searchpage';
import { NavigationManager } from '/navigationManager';
import { useStore, getStore} from '/store';
import { AudioManager } from '/audioManager';
import { FootnoteGloManager } from '/footnoteGloManager';


if (process.env.NODE_ENV==='development') {
	require('preact/debug');
}

//const cancel = awaitInstallPrompt();




function App(props){
	
	const toastRef = useRef(null);

	
	const [firstLoad, ] = getStore.firstLoad();
	if (firstLoad) {
		props.navManager.setInitialBook();
	}


	const fnGloManager = new FootnoteGloManager({toastRef: toastRef, navManager: props.navManager});


	return (
		<div class="mdl-layout mdl-js-layout mdl-layout--fixed-header">
			
			<PageHeader 
				navManager={props.navManager} /> 
			<BookRenderer 
				navManager={props.navManager}
				audioManager={props.audioManager}
				fnGloManager={fnGloManager}/>	
			<PageFooter 
				navManager={props.navManager}
				audioManager={props.audioManager}
				fnGloManager={fnGloManager} />
		</div>
	);
}


function Main() {
	const navManager = new NavigationManager	;
	const audioManager = new AudioManager({navManager: navManager});		

	
	return (
		
		<Router>
			<App default path="/" 
			    navManager={navManager} 
			    audioManager={audioManager} />
			<SearchPage path="/search" 
			    navManager={navManager} />
		</Router>
		
	);
}

if (typeof window !== "undefined") { 
	render(<Main />, document.body);
}

