import { h, render, Component, Fragment } from 'preact';

import { bookData } from '/bookData';
import { chapterData } from '/chapterdata';
import { configs } from '/configs';
import { useEffect, useLayoutEffect } from 'preact/hooks';
import { route } from 'preact-router';
import { getStore, useStore } from '/store';
import { resetPropWarnings } from 'preact/debug';

export function NavigationManager() {
    const [chapters, setChapters] = useStore.chapters();
	const [curChapter, setCurChapter] = useStore.curChapter();
    const [ , setFirstLoad] = useStore.firstLoad()
    const [curBook, setCurBook] = useStore.curBook();
    const [, setXmlData ] = useStore.xmlData();
    const [bookCode, setBookCode] = useStore.bookCode();
    const [ navTarget, setNavTarget] = useStore.navTarget();



    const parser = new DOMParser();
    const bookCodeToBook = {};
    bookData.forEach((x) => bookCodeToBook[x.code] = x);


    this.books = bookData;
    this.bookCode = bookCode;

    
    this.requestCptNavOnNum = (cptNum) => {
        var chapter = chapters[cptNum];
        this.requestCptNav(chapter.cid, chapter.number);
    }


    this.requestCptNav = (newAddress, cptNum) => {
		setCurChapter(cptNum);
       // console.log(newAddress);
		var elem = document.getElementById(newAddress);
		elem.scrollIntoView({behavior: "smooth", block: "start", inline: "start"});
	};


    this.navFromRef = (ref) => {
        route('/');
        var [bookCode, cptV] = ref.split(' ', 2); 
        if (bookCode in bookCodeToBook) {
            if (cptV.includes('-')) {
                cptV = cptV.split('-')[0];
            }
            setNavTarget(ref);
            setCurBook(bookCodeToBook[bookCode]);
        }
    };


    this.updateBook = (book) => {
        console.log("updateBook");
        setCurBook(book);
        
    };


    this.setInitialBook = () => {
        setCurBook(bookData[1]);
        setFirstLoad(false);
    }


    const updateBookData = (navTo=null) => {
        if (curBook) {
            fetch(curBook.fpath).then(resp => resp.text()).then((text) => {
                var xml = parser.parseFromString(text, 'text/xml');
                chapterData.length = 0;
                //var bookXml = xml.getElementsByTagName('html')[0];
                var bookCodeInfo = curBook.code; //bookXml.attributes.getNamedItem('code').value;
                setBookCode(bookCodeInfo);
                setXmlData(xml);
                setChapters(chapterData[bookCodeInfo]);
                setCurChapter(chapterData[bookCodeInfo][0].number);
                if (!navTarget) {
                    var elem = document.getElementById('mainelem');
                    if (elem) {
                        elem.scrollTop = 0;
                    }
                }
                return 'finished';
            });
        }
    }

    useEffect(updateBookData, [curBook]);
    
    return null;
    
}


